with seed(ord,teks_code,rit_band,difficulty,stem,stem_image_svg,explanation,source_note,choices) as (values
(1,$code$4.11C.iii$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence is complete and avoids a run-on?$stem$,NULL,$exp$A comma and conjunction correctly join the two complete thoughts.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The hikers stopped, and the guide checked the map.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"The hikers stopped the guide checked the map.","is_correct":false,"misconception":"Created a run-on or comma splice.","misconception_tag":"sentence_completeness","sort_order":2},{"label":"C","body":"The hikers stopped, the guide checked the map.","is_correct":false,"misconception":"Created a run-on or comma splice.","misconception_tag":"sentence_completeness","sort_order":3},{"label":"D","body":"The hikers, stopped and the guide, checked the map.","is_correct":false,"misconception":"Created a run-on or comma splice.","misconception_tag":"sentence_completeness","sort_order":4}]$choices$::jsonb),
(2,$code$4.11B.i$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which sentence would make the best introduction?$stem$,NULL,$exp$An introduction states the main idea.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"In conclusion, gardens are helpful.","is_correct":false,"misconception":"Chose a detail or conclusion instead of an introduction.","misconception_tag":"sequence_wrong_step","sort_order":1},{"label":"B","body":"School gardens help students learn in many ways.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"That is why gardens are useful.","is_correct":false,"misconception":"Chose a detail or conclusion instead of an introduction.","misconception_tag":"sequence_wrong_step","sort_order":3},{"label":"D","body":"First, water the plants.","is_correct":false,"misconception":"Chose a detail or conclusion instead of an introduction.","misconception_tag":"sequence_wrong_step","sort_order":4}]$choices$::jsonb),
(3,$code$4.11B.i$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which transition best begins a final paragraph?$stem$,NULL,$exp$In conclusion signals the ending paragraph.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Next,","is_correct":false,"misconception":"Chose a transition for a detail or sequence step.","misconception_tag":"sequence_wrong_step","sort_order":1},{"label":"B","body":"At first,","is_correct":false,"misconception":"Chose a transition for a detail or sequence step.","misconception_tag":"sequence_wrong_step","sort_order":2},{"label":"C","body":"In conclusion,","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"For example,","is_correct":false,"misconception":"Chose a transition for a detail or sequence step.","misconception_tag":"sequence_wrong_step","sort_order":4}]$choices$::jsonb),
(4,$code$4.11B.i$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence belongs in a conclusion?$stem$,NULL,$exp$A conclusion restates the main idea and wraps up reasons.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"One reason is that students need computers.","is_correct":false,"misconception":"Chose a supporting detail instead of a closing idea.","misconception_tag":"sequence_wrong_step","sort_order":1},{"label":"B","body":"For example, Priya used the printer.","is_correct":false,"misconception":"Chose a supporting detail instead of a closing idea.","misconception_tag":"sequence_wrong_step","sort_order":2},{"label":"C","body":"The library opens at nine.","is_correct":false,"misconception":"Chose a supporting detail instead of a closing idea.","misconception_tag":"sequence_wrong_step","sort_order":3},{"label":"D","body":"These reasons show why the library should stay open later.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(5,$code$4.11B.i$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which order is best for an essay?$stem$,NULL,$exp$A clear essay begins, develops, and ends.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"introduction, reasons, conclusion","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"reasons, conclusion, introduction","is_correct":false,"misconception":"Put essay parts in an illogical order.","misconception_tag":"sequence_wrong_step","sort_order":2},{"label":"C","body":"conclusion, introduction, reasons","is_correct":false,"misconception":"Put essay parts in an illogical order.","misconception_tag":"sequence_wrong_step","sort_order":3},{"label":"D","body":"introduction, conclusion, reasons","is_correct":false,"misconception":"Put essay parts in an illogical order.","misconception_tag":"sequence_wrong_step","sort_order":4}]$choices$::jsonb),
(6,$code$4.11B.ii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which detail best supports: Exercise helps students focus?$stem$,NULL,$exp$The detail directly supports focus after exercise.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The hallway has lockers.","is_correct":false,"misconception":"Picked an unrelated detail.","misconception_tag":"response_off_topic_or_vague","sort_order":1},{"label":"B","body":"After running, our class listened carefully.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"My shoes are blue.","is_correct":false,"misconception":"Picked an unrelated detail.","misconception_tag":"response_off_topic_or_vague","sort_order":3},{"label":"D","body":"Lunch was pizza.","is_correct":false,"misconception":"Picked an unrelated detail.","misconception_tag":"response_off_topic_or_vague","sort_order":4}]$choices$::jsonb),
(7,$code$4.11B.ii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence adds the most specific detail?$stem$,NULL,$exp$Specific details name what, where, and how long.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"It was nice.","is_correct":false,"misconception":"Chose a vague detail.","misconception_tag":"response_off_topic_or_vague","sort_order":1},{"label":"B","body":"The thing happened outside.","is_correct":false,"misconception":"Chose a vague detail.","misconception_tag":"response_off_topic_or_vague","sort_order":2},{"label":"C","body":"The butterfly rested on a milkweed leaf for ten minutes.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"The butterfly was there.","is_correct":false,"misconception":"Chose a vague detail.","misconception_tag":"response_off_topic_or_vague","sort_order":4}]$choices$::jsonb),
(8,$code$4.11B.ii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which detail does not belong in a paragraph about recycling?$stem$,NULL,$exp$The cousin sentence is off topic.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Glass bottles can be reused.","is_correct":false,"misconception":"Did not identify the unrelated detail.","misconception_tag":"response_off_topic_or_vague","sort_order":1},{"label":"B","body":"Paper can be sorted into bins.","is_correct":false,"misconception":"Did not identify the unrelated detail.","misconception_tag":"response_off_topic_or_vague","sort_order":2},{"label":"C","body":"Recycling keeps some trash out of landfills.","is_correct":false,"misconception":"Did not identify the unrelated detail.","misconception_tag":"response_off_topic_or_vague","sort_order":3},{"label":"D","body":"My cousin plays soccer after school.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(9,$code$4.11B.ii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which revision develops the idea best?$stem$,NULL,$exp$The best revision explains why the aquifer matters.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The aquifer matters because cities use its water during dry months.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"The aquifer matters a lot.","is_correct":false,"misconception":"Chose a vague or underdeveloped detail.","misconception_tag":"response_off_topic_or_vague","sort_order":2},{"label":"C","body":"Water is good.","is_correct":false,"misconception":"Chose a vague or underdeveloped detail.","misconception_tag":"response_off_topic_or_vague","sort_order":3},{"label":"D","body":"The aquifer is a thing underground.","is_correct":false,"misconception":"Chose a vague or underdeveloped detail.","misconception_tag":"response_off_topic_or_vague","sort_order":4}]$choices$::jsonb),
(10,$code$4.11B.ii$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which detail best supports an essay about safe biking?$stem$,NULL,$exp$The helmet detail directly supports the idea of safe biking.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The park has many trees.","is_correct":false,"misconception":"Picked an interesting but weak or off-topic detail.","misconception_tag":"response_off_topic_or_vague","sort_order":1},{"label":"B","body":"A helmet can protect a rider during a fall.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"My bike is green and shiny.","is_correct":false,"misconception":"Picked an interesting but weak or off-topic detail.","misconception_tag":"response_off_topic_or_vague","sort_order":3},{"label":"D","body":"I like riding after dinner.","is_correct":false,"misconception":"Picked an interesting but weak or off-topic detail.","misconception_tag":"response_off_topic_or_vague","sort_order":4}]$choices$::jsonb),
(11,$code$4.3D$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which sentence uses right correctly?$stem$,NULL,$exp$Right can mean the opposite of left.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The right barked loudly.","is_correct":false,"misconception":"Chose a sentence where the homograph meaning does not fit.","misconception_tag":"vocab_skipped_context_clues","sort_order":1},{"label":"B","body":"She ate a right apple.","is_correct":false,"misconception":"Chose a sentence where the homograph meaning does not fit.","misconception_tag":"vocab_skipped_context_clues","sort_order":2},{"label":"C","body":"Turn right at the corner.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"I will right my bike to school.","is_correct":false,"misconception":"Chose a sentence where the homograph meaning does not fit.","misconception_tag":"vocab_skipped_context_clues","sort_order":4}]$choices$::jsonb),
(12,$code$4.3D$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the meaning of bat in: The bat flew at dusk.$stem$,NULL,$exp$At dusk and flew show bat means the animal.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"a wooden sports tool","is_correct":false,"misconception":"Ignored context clues for a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":1},{"label":"B","body":"to blink","is_correct":false,"misconception":"Ignored context clues for a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":2},{"label":"C","body":"a flat board","is_correct":false,"misconception":"Ignored context clues for a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":3},{"label":"D","body":"a flying mammal","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(13,$code$4.3D$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the correct word: Please ___ your name clearly.$stem$,NULL,$exp$Write means to form words.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"write","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"right","is_correct":false,"misconception":"Confused homophones.","misconception_tag":"vocab_skipped_context_clues","sort_order":2},{"label":"C","body":"rite","is_correct":false,"misconception":"Confused homophones.","misconception_tag":"vocab_skipped_context_clues","sort_order":3},{"label":"D","body":"wright","is_correct":false,"misconception":"Confused homophones.","misconception_tag":"vocab_skipped_context_clues","sort_order":4}]$choices$::jsonb),
(14,$code$4.3D$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Choose the meaning of present: The present speaker is Dr. Lee.$stem$,NULL,$exp$Present describes the speaker who is here now.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"the past tense","is_correct":false,"misconception":"Used the wrong meaning of a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":1},{"label":"B","body":"currently here","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"a gift","is_correct":false,"misconception":"Used the wrong meaning of a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":3},{"label":"D","body":"to give formally","is_correct":false,"misconception":"Used the wrong meaning of a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":4}]$choices$::jsonb),
(15,$code$4.3D$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence uses close as an adjective?$stem$,NULL,$exp$Close describes distance, so it is an adjective here.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"They close the store at six.","is_correct":false,"misconception":"Confused verb and adjective meanings of a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":1},{"label":"B","body":"We will close the meeting now.","is_correct":false,"misconception":"Confused verb and adjective meanings of a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":2},{"label":"C","body":"The store is close to my house.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Please close the door.","is_correct":false,"misconception":"Confused verb and adjective meanings of a homograph.","misconception_tag":"vocab_skipped_context_clues","sort_order":4}]$choices$::jsonb),
(16,$code$4.3E$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which word is the best synonym for happy?$stem$,NULL,$exp$Joyful has a similar meaning to happy.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"angry","is_correct":false,"misconception":"Chose an antonym or unrelated word.","misconception_tag":"confused_synonym_with_antonym","sort_order":1},{"label":"B","body":"tired","is_correct":false,"misconception":"Chose an antonym or unrelated word.","misconception_tag":"confused_synonym_with_antonym","sort_order":2},{"label":"C","body":"silent","is_correct":false,"misconception":"Chose an antonym or unrelated word.","misconception_tag":"confused_synonym_with_antonym","sort_order":3},{"label":"D","body":"joyful","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(17,$code$4.3E$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which word could replace tiny?$stem$,NULL,$exp$Small is a synonym for tiny.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"small","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"huge","is_correct":false,"misconception":"Confused synonym with antonym or unrelated word.","misconception_tag":"confused_synonym_with_antonym","sort_order":2},{"label":"C","body":"heavy","is_correct":false,"misconception":"Confused synonym with antonym or unrelated word.","misconception_tag":"confused_synonym_with_antonym","sort_order":3},{"label":"D","body":"late","is_correct":false,"misconception":"Confused synonym with antonym or unrelated word.","misconception_tag":"confused_synonym_with_antonym","sort_order":4}]$choices$::jsonb),
(18,$code$4.3E$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$A thesaurus would help you find ___.$stem$,NULL,$exp$A thesaurus lists synonyms and related words.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"the capital of Texas","is_correct":false,"misconception":"Confused a thesaurus with other reference tools.","misconception_tag":"confused_synonym_with_antonym","sort_order":1},{"label":"B","body":"a stronger word for said","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"the page number of a chapter","is_correct":false,"misconception":"Confused a thesaurus with other reference tools.","misconception_tag":"confused_synonym_with_antonym","sort_order":3},{"label":"D","body":"the pronunciation of a word","is_correct":false,"misconception":"Confused a thesaurus with other reference tools.","misconception_tag":"confused_synonym_with_antonym","sort_order":4}]$choices$::jsonb),
(19,$code$4.3E$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which word best replaces walked in: Hana walked quietly into the room?$stem$,NULL,$exp$Tiptoed gives a more exact quiet way of walking.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"shouted","is_correct":false,"misconception":"Chose a word that changes the meaning.","misconception_tag":"confused_synonym_with_antonym","sort_order":1},{"label":"B","body":"dropped","is_correct":false,"misconception":"Chose a word that changes the meaning.","misconception_tag":"confused_synonym_with_antonym","sort_order":2},{"label":"C","body":"tiptoed","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"sprinted","is_correct":false,"misconception":"Chose a word that changes the meaning.","misconception_tag":"confused_synonym_with_antonym","sort_order":4}]$choices$::jsonb),
(20,$code$4.3E$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which replacement keeps the meaning but improves precision? The storm was big.$stem$,NULL,$exp$Enormous is a more precise synonym for big.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The storm was tiny.","is_correct":false,"misconception":"Chose an antonym or nonsensical replacement.","misconception_tag":"confused_synonym_with_antonym","sort_order":1},{"label":"B","body":"The storm was cheerful.","is_correct":false,"misconception":"Chose an antonym or nonsensical replacement.","misconception_tag":"confused_synonym_with_antonym","sort_order":2},{"label":"C","body":"The storm was wooden.","is_correct":false,"misconception":"Chose an antonym or nonsensical replacement.","misconception_tag":"confused_synonym_with_antonym","sort_order":3},{"label":"D","body":"The storm was enormous.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb)
), ins as (
  insert into map_questions(subject,grade,standard_id,passage_id,rit_band,difficulty,stem,stem_image_svg,audio_supported,explanation,source_note,is_active,question_format)
  select 'language'::map_subject,4,s.id,null,seed.rit_band,seed.difficulty,seed.stem,seed.stem_image_svg,true,seed.explanation,seed.source_note,true,'mcq'
  from seed
  join map_standards s on s.grade=4 and s.subject='language'::map_subject and s.teks_code=seed.teks_code
  where not exists (
    select 1 from map_questions q
    where q.grade=4 and q.subject='language'::map_subject and q.source_note=seed.source_note and q.stem=seed.stem and q.explanation=seed.explanation
  )
  returning id, stem, explanation, source_note
)
insert into map_question_choices(question_id,label,body,body_image_svg,is_correct,misconception,misconception_tag,sort_order)
select ins.id,c.label,c.body,null,c.is_correct,c.misconception,c.misconception_tag,c.sort_order
from ins
join seed on seed.stem=ins.stem and seed.explanation=ins.explanation and seed.source_note=ins.source_note
cross join lateral jsonb_to_recordset(seed.choices) as c(label char(1), body text, is_correct boolean, misconception text, misconception_tag text, sort_order smallint);